custom_css:
[selector = "reinsurer-item"]{
    padding: 1.5rem;
    background-color: #EEEEEE;
    border: 1px solid #BFBFBF;
    border-radius: 15px;
    box-shadow: 2px 2px 4px rgba(0, 0, 0, 0.404);
    margin-top: 2rem;
    margin-bottom: 2rem;
}

[selector = "city-item"]{
    padding: 1.5rem;
    background-color: #ffffff;
    border: 1px solid #BFBFBF;
    border-radius: 15px;
    box-shadow: 2px 2px 4px rgba(0, 0, 0, 0.404);
    margin-top: 2rem;
    margin-bottom: 2rem;
}


[selector = "address-item"]{
    padding: 1.5rem;
    border: 1px solid #BFBFBF;
    border-radius: 15px;
    box-shadow: 2px 2px 4px rgba(0, 0, 0, 0.404);
    margin-top: 2rem;
    margin-bottom: 2rem;
}



[selector='city-item'] [title='Add Item'] i::after {
  content: ' Add City' !important;
}

[selector='city-item'] [title='Delete Item'] i::after {
  content: ' Delete City' !important;
}

[selector='address-item'] [title='Add Item'] i::after {
  content: ' Add Address' !important;
}

[selector='city-item'] [selector='address-item'] [title='Delete Item'] i::after {
  content: ' Delete Address' !important;
}

[selector="grid-content"] {
    border: 1px solid #D7E023;
}
[selector="grid-content"] .container-fluid {
    border-top: 1px solid #c5c5c542;
}
[selector="grid-content"] .container-fluid .row > div {
border-right: 1px solid #c5c5c542;
}
[selector="grid-content"] .container-fluid .row > div:last-child {
  border-right: 0px;
}
[selector="grid-content"] > div>div:nth-child(2n+1) {
    background-color: #EDEDED;
}
